+    const { resizeHandler, scrollHandler } = dropdown._smlActionDropdownListeners;
+    if (resizeHandler) globalThis.removeEventListener("resize", resizeHandler);
+    if (scrollHandler) globalThis.removeEventListener("scroll", scrollHandler, true);
+    dropdown._smlActionDropdownListeners = null;
+  }
