+
+function openFloatingRowActionDropdown(dropdown) {
+  if (!(dropdown instanceof HTMLElement)) return;
+
+  const menu = dropdown.querySelector(":scope > .dropdown-menu");
+  const trigger = getActionDropdownTrigger(dropdown);
+  if (!(menu instanceof HTMLElement) || !(trigger instanceof HTMLElement)) return;
+
+  cleanupFloatingRowActionDropdowns(dropdown.closest("table"), dropdown);
+
+  dropdown.classList.add("show");
+  menu.classList.add("show");
+  trigger.setAttribute("aria-expanded", "true");
+
+  restoreFloatingRowActionDropdown(dropdown);
+  positionFloatingRowActionDropdown(dropdown);
